#include<bits/stdc++.h>
using namespace std;
int n,tot,v[400010],l1[200010],r1[200010],l2[200010],r2[200010];
long long a[400010],b[400010],c[400010],d[400010],e[400010],f[400010];
int main()
{
    int id,t;
    scanf("%d%d",&id,&t);
    while(t--)
    {
        for(int i=1;i<=tot;i++)
        {
            a[i]=b[i]=c[i]=d[i]=e[i]=f[i]=0;
            l1[i]=l2[i]=r1[i]=r2[i]=0;
            v[i]=0;
        }
        n=tot=0;
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
        {
            scanf("%d%d%d%d",&l1[i],&r1[i],&l2[i],&r2[i]);
            v[++tot]=l2[i];
            v[++tot]=r2[i]+1;
        }
        sort(v+1,v+1+tot);
        tot=unique(v+1,v+1+tot)-v-1;
        for(int i=1;i<=n;i++)
        {
            int x=lower_bound(v+1,v+1+tot,l2[i])-v,y=lower_bound(v+1,v+1+tot,r2[i]+1)-v;
            a[x]+=r1[i],a[y]-=r1[i];
            b[y]+=l1[i],c[y]+=r1[i];
            d[1]+=l1[i],d[x]-=l1[i];
            e[1]+=r1[i],e[x]-=r1[i];
            f[x]++,f[y]--;
        }
        for(int i=1;i<=tot;i++)
        {
            a[i]+=a[i-1];
            b[i]+=b[i-1];
            c[i]+=c[i-1];
            d[i]+=d[i-1];
            e[i]+=e[i-1];
            f[i]+=f[i-1];
        }
        long long ans=0;
        for(int i=1;i<tot;i++)
        {
            if(f[i]&&max(b[i]-a[i]+1,d[i])<=min(a[i]+c[i],e[i]))
            {
                ans+=v[i+1]-v[i];
            }
        }
        printf("%lld\n",ans);
    }
    return 0;
}
